function getAllLessons() {
  return sections.flatMap((s2) => s2.lessons);
}
function getLessonById(id) {
  return getAllLessons().find((l) => l.id === id);
}
function getSectionById(id) {
  return sections.find((s2) => s2.id === id);
}
